// syncLoop runs in the background and periodically flushes the buffer
// to the OS and then fsyncs to stable storage.
func (w *WAL) syncLoop() {
	defer w.wg.Done()
	ticker := time.NewTicker(100 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			w.Sync()
		case <-w.closeCh:
			// Final sync before shutdown
			w.Sync()
			return
		}
	}
